**Express API with CSP Headers**:
```typescript
// svg-upload.controller.ts
import express, { Request, Response, NextFunction } from 'express';
import multer from 'multer';
import helmet from 'helmet';
import rateLimit from 'express-rate-limit';
import { SvgSanitizer } from './svg-sanitizer.service';
import { AuditLogger } from './audit-logger';
import crypto from 'crypto';
import fs from 'fs/promises';
import path from 'path';

const app = express();

// Security headers including strict CSP
app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'"],  // No inline scripts allowed
      styleSrc: ["'self'", "'unsafe-inline'"],  // SVG may need inline styles
      imgSrc: ["'self'", "data:", "blob:"],
      objectSrc: ["'none'"],  // Block <object> tags
      baseUri: ["'self'"],
      frameAncestors: ["'none'"]
    }
  }
}));

// Rate limiting for upload endpoint
const uploadLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 10, // 10 uploads per window
  message: { error: 'Too many uploads, please try again later' },
  standardHeaders: true,
  legacyHeaders: false
});

const upload = multer({
  dest: 'uploads/temp/',
  limits: { 
    fileSize: 50 * 1024, // 50KB max
    files: 1
  },
  fileFilter: (req, file, cb) => {
    const allowedMimes = ['image/svg+xml'];
    if (!allowedMimes.includes(file.mimetype)) {
      return cb(new Error('Invalid file type'));
    }
    cb(null, true);
  }
});

app.post('/api/svg/upload',
  uploadLimiter,
  upload.single('svg'),
  async (req: Request, res: Response, next: NextFunction) => {
    const requestId = crypto.randomUUID();
    const userId = (req as any).user?.id || 'anonymous';

    AuditLogger.log({
      event: 'SVG_UPLOAD_ATTEMPT',
      requestId,
      userId,
      ip: req.ip,
      timestamp: new Date().toISOString()
    });

    if (!req.file) {
      return res.status(400).json({ error: 'No file uploaded' });
    }

    try {
      const rawContent = await fs.readFile(req.file.path, 'utf-8');

      // Sanitize SVG
      const result = SvgSanitizer.sanitize(rawContent);

      // Clean up temp file immediately
      await fs.unlink(req.file.path).catch(() => {});

      if (!result.success || !result.sanitizedSvg) {
        AuditLogger.log({
          event: 'SVG_UPLOAD_BLOCKED',
          requestId,
          userId,
          reason: result.errors.join(', '),
          timestamp: new Date().toISOString()
        });

        return res.status(400).json({ 
          error: 'SVG failed security validation',
          details: process.env.NODE_ENV === 'development' ? result.errors : undefined
        });
      }

      // Store sanitized SVG
      const svgId = crypto.randomUUID();
      const storagePath = path.join('storage', 'svgs', `${svgId}.svg`);
      await fs.mkdir(path.dirname(storagePath), { recursive: true });
      await fs.writeFile(storagePath, result.sanitizedSvg, 'utf-8');

      AuditLogger.log({
        event: 'SVG_UPLOAD_SUCCESS',
        requestId,
        userId,
        svgId,
        interactiveElements: result.interactiveElements.length,
        timestamp: new Date().toISOString()
      });

      res.json({
        svgId,
        interactiveElements: result.interactiveElements
      });

    } catch (error) {
      AuditLogger.log({
        event: 'SVG_UPLOAD_ERROR',
        requestId,
        userId,
        error: error instanceof Error ? error.message : 'Unknown error',
        timestamp: new Date().toISOString()
      });

      next(error);
    }
  }
);

// Serve SVG with security headers
app.get('/api/svg/:id', async (req: Request, res: Response) => {
  const svgId = req.params.id;

  // Validate ID format (UUID only)
  if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(svgId)) {
    return res.status(400).json({ error: 'Invalid SVG ID' });
  }

  const filePath = path.join('storage', 'svgs', `${svgId}.svg`);

  try {
    const content = await fs.readFile(filePath, 'utf-8');

    res.set({
      'Content-Type': 'image/svg+xml',
      'X-Content-Type-Options': 'nosniff',
      'Content-Disposition': 'inline',
      'Cache-Control': 'public, max-age=31536000, immutable'
    });

    res.send(content);
  } catch {
    res.status(404).json({ error: 'SVG not found' });
  }
});
