**Key Security Controls**:
- **DOMPurify sanitization**: Industry-standard library that strips malicious HTML/JS while preserving safe formatting
- **Strict allowlist**: Only permits specific safe tags and attributes, blocks all event handlers
- **Link hardening**: Forces `target="_blank"` and `rel="noopener noreferrer"` on all links to prevent tab-nabbing
- **React's default escaping**: Text content in JSX expressions is automatically escaped

For rich content requirements, you need a defense-in-depth approach: parse structured content formats (like Markdown), use iframe sandboxing for embeds, implement Content Security Policy, and add server-side validation as a second layer.

**PRODUCTION PATTERN**:

```react
import React, { useState, useEffect, useMemo, useCallback } from 'react';
import DOMPurify from 'dompurify';
import { marked } from 'marked';
import hljs from 'highlight.js';

// ============================================
// SECURITY CONFIGURATION
// ============================================

const TRUSTED_EMBED_DOMAINS = [
  'youtube.com',
  'www.youtube.com',
  'player.vimeo.com',
  'codepen.io',
  'codesandbox.io'
];

// Strict DOMPurify configuration
const createSanitizeConfig = (allowRichContent = false) => ({
  ALLOWED_TAGS: allowRichContent 
    ? ['b', 'i', 'em', 'strong', 'a', 'p', 'br', 'ul', 'ol', 'li', 
       'code', 'pre', 'blockquote', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6',
       'table', 'thead', 'tbody', 'tr', 'th', 'td', 'hr', 'span', 'div']
    : ['b', 'i', 'em', 'strong', 'a', 'p', 'br'],
  ALLOWED_ATTR: ['href', 'title', 'class', 'id', 'colspan', 'rowspan'],
  ALLOW_DATA_ATTR: false,
  FORBID_TAGS: ['script', 'style', 'iframe', 'object', 'embed', 'form', 
                'input', 'button', 'textarea', 'select', 'meta', 'link'],
  FORBID_ATTR: ['onerror', 'onload', 'onclick', 'onmouseover', 'onfocus',
                'onblur', 'onsubmit', 'onreset', 'onkeydown', 'onkeyup',
                'style'],  // Block inline styles to prevent CSS injection
  USE_PROFILES: { html: true },
  RETURN_DOM_FRAGMENT: false,
  RETURN_DOM: false
});

// Configure marked for secure Markdown parsing
marked.setOptions({
  headerIds: false,
  mangle: false,
  highlight: (code, lang) => {
    try {
      if (lang && hljs.getLanguage(lang)) {
        return hljs.highlight(code, { language: lang }).value;
      }
      return hljs.highlightAuto(code).value;
    } catch (e) {
      console.error('Highlight error:', e);
      return code;
    }
  },
  // SECURITY: Disable raw HTML in Markdown
  sanitize: false, // We use DOMPurify instead
});

// Custom renderer to prevent XSS in links
const renderer = new marked.Renderer();
renderer.link = (href, title, text) => {
  // Validate URL protocol
  const allowedProtocols = ['http:', 'https:', 'mailto:'];
  try {
    const url = new URL(href, window.location.origin);
    if (!allowedProtocols.includes(url.protocol)) {
      return text; // Return plain text for dangerous protocols
    }
  } catch {
    return text; // Invalid URL, return plain text
  }

  const titleAttr = title ? ` title="${DOMPurify.sanitize(title)}"` : '';
  return `<a href="${DOMPurify.sanitize(href)}"${titleAttr} target="_blank" rel="noopener noreferrer">${text}</a>`;
};
marked.use({ renderer });

// ============================================
// SECURE CONTENT COMPONENTS
// ============================================

// Safe embed component with iframe sandboxing
function SecureEmbed({ url, title = 'Embedded content' }) {
  const isAllowed = useMemo(() => {
    try {
      const embedUrl = new URL(url);
      return TRUSTED_EMBED_DOMAINS.includes(embedUrl.hostname);
    } catch {
      return false;
    }
  }, [url]);

  if (!isAllowed) {
    return (
      <div className="embed-blocked">
        <p>⚠️ Embed from untrusted domain blocked</p>
        <a href={url} target="_blank" rel="noopener noreferrer">
          View external content
        </a>
      </div>
    );
  }

  return (
    <iframe
      src={url}
      title={title}
      sandbox="allow-scripts allow-same-origin allow-popups"
      allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope"
      referrerPolicy="strict-origin-when-cross-origin"
      loading="lazy"
      className="secure-embed"
    />
  );
}

// Rich content renderer with full sanitization
function RichContent({ content, format = 'markdown', allowEmbeds = false }) {
  const sanitizedHtml = useMemo(() => {
    if (!content || typeof content !== 'string') return '';

    let html;
    switch (format) {
      case 'markdown':
        html = marked.parse(content);
        break;
      case 'html':
        html = content;
        break;
      default:
        // Plain text - escape everything
        return content
          .replace(/&/g, '&amp;')
          .replace(/</g, '&lt;')
          .replace(/>/g, '&gt;');
    }

    // Apply DOMPurify sanitization
    const config = createSanitizeConfig(true);
    return DOMPurify.sanitize(html, config);
  }, [content, format]);

  // Extract and render embeds separately
  const embeds = useMemo(() => {
    if (!allowEmbeds || !content) return [];
    const embedRegex = /\[embed\](.+?)\[\/embed\]/g;
    const matches = [];
    let match;
    while ((match = embedRegex.exec(content)) !== null) {
      matches.push(match[1]);
    }
    return matches;
  }, [content, allowEmbeds]);

  return (
    <div className="rich-content">
      <div dangerouslySetInnerHTML={{ __html: sanitizedHtml }} />
      {embeds.map((embedUrl, index) => (
        <SecureEmbed key={index} url={embedUrl} />
      ))}
    </div>
  );
}

