// safe-html.service.ts - Production-grade HTML sanitization service
import { Injectable, SecurityContext } from '@angular/core';
import { DomSanitizer } from '@angular/platform-browser';
import DOMPurify from 'dompurify';

// Strict allowlist for rich text content
const ALLOWED_TAGS = [
  'p', 'br', 'b', 'i', 'u', 'strong', 'em', 'ul', 'ol', 'li',
  'h1', 'h2', 'h3', 'h4', 'h5', 'h6', 'blockquote', 'code', 'pre',
  'a', 'img', 'table', 'thead', 'tbody', 'tr', 'th', 'td'
];

const ALLOWED_ATTRIBUTES = {
  'a': ['href', 'title', 'rel'],
  'img': ['src', 'alt', 'width', 'height'],
  'td': ['colspan', 'rowspan'],
  'th': ['colspan', 'rowspan'],
  '*': ['class']  // Allow class on all elements for styling
};

// Allowed URL schemes
const ALLOWED_URI_REGEXP = /^(?:(?:https?|mailto):|[^a-z]|[a-z+.\-]+(?:[^a-z+.\-:]|$))/i;

@Injectable({ providedIn: 'root' })
export class SafeHtmlService {
  private purifyConfig: DOMPurify.Config;

  constructor(private sanitizer: DomSanitizer) {
    // Configure DOMPurify with strict settings
    this.purifyConfig = {
      ALLOWED_TAGS: ALLOWED_TAGS,
      ALLOWED_ATTR: Object.values(ALLOWED_ATTRIBUTES).flat(),
      ALLOWED_URI_REGEXP: ALLOWED_URI_REGEXP,
      ALLOW_DATA_ATTR: false,
      ALLOW_UNKNOWN_PROTOCOLS: false,
      RETURN_DOM: false,
      RETURN_DOM_FRAGMENT: false,
      RETURN_TRUSTED_TYPE: true,  // Enable Trusted Types
      SANITIZE_DOM: true,
      KEEP_CONTENT: true,
      IN_PLACE: false,
      USE_PROFILES: { html: true },
      // Remove dangerous elements completely
      FORBID_TAGS: ['script', 'style', 'iframe', 'object', 'embed', 'form', 'input', 'button'],
      FORBID_ATTR: ['onerror', 'onload', 'onclick', 'onmouseover', 'onfocus', 'onblur']
    };

    // Add hooks for additional sanitization
    this.setupDOMPurifyHooks();
  }

  private setupDOMPurifyHooks(): void {
    // Hook to sanitize URLs in href and src attributes
    DOMPurify.addHook('uponSanitizeAttribute', (node, data) => {
      if (data.attrName === 'href' || data.attrName === 'src') {
        const url = data.attrValue;

        // Block javascript: URLs
        if (url.toLowerCase().startsWith('javascript:')) {
          data.attrValue = '';
          console.warn('Blocked javascript: URL in sanitization');
        }

        // Block data: URLs for non-images
        if (url.toLowerCase().startsWith('data:') && data.attrName !== 'src') {
          data.attrValue = '';
          console.warn('Blocked data: URL in non-image attribute');
        }

        // Ensure links open safely
        if (data.attrName === 'href' && node.tagName === 'A') {
          (node as HTMLAnchorElement).setAttribute('rel', 'noopener noreferrer');
          (node as HTMLAnchorElement).setAttribute('target', '_blank');
        }
      }
    });

    // Hook to remove suspicious CSS
    DOMPurify.addHook('afterSanitizeAttributes', (node) => {
      if (node.hasAttribute('style')) {
        const style = node.getAttribute('style') || '';
        // Remove expression() and url() from inline styles
        const safeStyle = style
          .replace(/expression\s*\([^)]*\)/gi, '')
          .replace(/url\s*\([^)]*\)/gi, '')
          .replace(/javascript:/gi, '');
        node.setAttribute('style', safeStyle);
      }
    });
  }

  sanitizeHtml(untrustedHtml: string): string {
    if (!untrustedHtml || typeof untrustedHtml !== 'string') {
      return '';
    }

    // First pass: DOMPurify sanitization
    const purified = DOMPurify.sanitize(untrustedHtml, this.purifyConfig);

    // Second pass: Angular's sanitizer for additional protection
    const angularSanitized = this.sanitizer.sanitize(
      SecurityContext.HTML,
      purified.toString()
    );

    return angularSanitized || '';
  }

  // Validate that content only contains expected elements
  validateStructure(html: string): { valid: boolean; issues: string[] } {
    const issues: string[] = [];
    const doc = new DOMParser().parseFromString(html, 'text/html');

    // Check for unexpected elements
    const allElements = doc.body.querySelectorAll('*');
    allElements.forEach((el) => {
      if (!ALLOWED_TAGS.includes(el.tagName.toLowerCase())) {
        issues.push(`Unexpected element: ${el.tagName}`);
      }
    });

    return {
      valid: issues.length === 0,
      issues
    };
  }
}
