// csp-nonce.service.ts - Server-side nonce generation and injection
import { Injectable, Inject, Optional } from '@angular/core';
import { DOCUMENT } from '@angular/common';
import { REQUEST } from '@nguniversal/express-engine/tokens';
import { Request } from 'express';
import * as crypto from 'crypto';

@Injectable({ providedIn: 'root' })
export class CspNonceService {
  private _nonce: string = '';

  constructor(
    @Inject(DOCUMENT) private document: Document,
    @Optional() @Inject(REQUEST) private request: Request
  ) {
    this._nonce = this.generateOrRetrieveNonce();
  }

  private generateOrRetrieveNonce(): string {
    // Server-side: Generate cryptographically secure nonce
    if (this.request) {
      // Check if nonce already set by middleware
      const existingNonce = (this.request as any).cspNonce;
      if (existingNonce) {
        return existingNonce;
      }

      // Generate new nonce
      const nonce = crypto.randomBytes(16).toString('base64');
      (this.request as any).cspNonce = nonce;
      return nonce;
    }

    // Client-side: Retrieve from injected meta tag
    const metaTag = this.document.querySelector('meta[name="csp-nonce"]');
    if (metaTag) {
      return metaTag.getAttribute('content') || '';
    }

    return '';
  }

  get nonce(): string {
    return this._nonce;
  }

  // Apply nonce to dynamically created script/style elements
  applyNonceToElement(element: HTMLScriptElement | HTMLStyleElement): void {
    if (this._nonce) {
      element.setAttribute('nonce', this._nonce);
    }
  }
}
