// csp-report.service.ts - CSP violation reporting and monitoring
import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { environment } from '../environments/environment';

interface CspViolation {
  documentUri: string;
  violatedDirective: string;
  blockedUri: string;
  sourceFile?: string;
  lineNumber?: number;
  columnNumber?: number;
  timestamp: Date;
  userAgent: string;
}

@Injectable({ providedIn: 'root' })
export class CspReportService {
  private readonly reportEndpoint = environment.cspReportEndpoint;
  private violationCache: Map<string, number> = new Map();
  private readonly RATE_LIMIT_WINDOW = 60000; // 1 minute
  private readonly MAX_REPORTS_PER_WINDOW = 10;

  constructor(private http: HttpClient) {
    this.setupViolationListener();
  }

  private setupViolationListener(): void {
    if (typeof document !== 'undefined') {
      document.addEventListener('securitypolicyviolation', (e) => {
        this.handleViolation(e);
      });
    }
  }

  private handleViolation(event: SecurityPolicyViolationEvent): void {
    const violation: CspViolation = {
      documentUri: event.documentURI,
      violatedDirective: event.violatedDirective,
      blockedUri: event.blockedURI,
      sourceFile: event.sourceFile,
      lineNumber: event.lineNumber,
      columnNumber: event.columnNumber,
      timestamp: new Date(),
      userAgent: navigator.userAgent
    };

    // Rate limiting to prevent DoS on reporting endpoint
    const cacheKey = `${violation.violatedDirective}:${violation.blockedUri}`;
    const currentCount = this.violationCache.get(cacheKey) || 0;

    if (currentCount < this.MAX_REPORTS_PER_WINDOW) {
      this.violationCache.set(cacheKey, currentCount + 1);

      // Report to backend for analysis
      this.http.post(this.reportEndpoint, {
        type: 'csp-violation',
        data: violation
      }).subscribe({
        error: (err) => console.error('Failed to report CSP violation:', err)
      });

      // Log locally for debugging
      console.warn('CSP Violation detected:', violation);

      // Reset rate limit after window
      setTimeout(() => {
        this.violationCache.delete(cacheKey);
      }, this.RATE_LIMIT_WINDOW);
    }
  }
}
