// Sanitize SVG content to remove all executable code
function sanitizeSVG(svgContent: string): string {
  const window = new JSDOM('').window;
  const purify = DOMPurify(window);

  // Configure DOMPurify for SVG with strict settings
  const cleanSVG = purify.sanitize(svgContent, {
    USE_PROFILES: { svg: true, svgFilters: true },
    FORBID_TAGS: ['script', 'foreignObject', 'use', 'animate', 'set'],
    FORBID_ATTR: [
      'onload', 'onclick', 'onerror', 'onmouseover', 'onmouseout',
      'onfocus', 'onblur', 'href', 'xlink:href', 'data', 'formaction'
    ],
    ADD_TAGS: ['svg', 'path', 'circle', 'rect', 'line', 'polyline', 
               'polygon', 'ellipse', 'g', 'defs', 'clipPath', 'text', 'tspan'],
    ADD_ATTR: ['viewBox', 'width', 'height', 'fill', 'stroke', 'stroke-width',
               'd', 'cx', 'cy', 'r', 'x', 'y', 'transform', 'opacity'],
  });

  return cleanSVG;
}

// Validate SVG structure
function isValidSVGStructure(content: string): boolean {
  try {
    const dom = new JSDOM(content, { contentType: 'image/svg+xml' });
    const doc = dom.window.document;
    const svg = doc.querySelector('svg');

    if (!svg) return false;

    // Check for dangerous elements
    const dangerousElements = doc.querySelectorAll(
      'script, foreignObject, iframe, embed, object, use[href], animate, set'
    );
    if (dangerousElements.length > 0) return false;

    // Check for event handlers in any element
    const allElements = doc.querySelectorAll('*');
    for (const el of allElements) {
      for (const attr of el.attributes) {
        if (attr.name.startsWith('on') || 
            attr.name.includes('href') && attr.value.startsWith('javascript:')) {
          return false;
        }
      }
    }

    return true;
  } catch {
    return false;
  }
}

