**Key Security Controls**:
- **DOMPurify sanitization**: Strips all script tags, event handlers, and dangerous elements from SVG content
- **Structural validation**: Parses the SVG as XML and checks for malicious patterns before sanitization
- **Content-Security-Policy header**: `script-src 'none'` prevents any inline scripts from executing even if sanitization is bypassed
- **Allowlist approach**: Only permits known-safe SVG elements and attributes
- **Random filenames**: Prevents path traversal and predictable file access

Supporting animated SVGs safely requires careful consideration as SMIL animations (`<animate>`, `<set>`) can be exploited. External references (`<use>`, `xlink:href`) are even more dangerous as they can load malicious content from attacker-controlled domains.

**PRODUCTION PATTERN**:

```typescript
// svg-sanitizer.service.ts
import DOMPurify from 'isomorphic-dompurify';
import { JSDOM } from 'jsdom';
import { createHash } from 'crypto';
import { Logger } from './logger';

interface SanitizationOptions {
  allowAnimations: boolean;
  allowExternalRefs: boolean;
  maxFileSize: number;
  allowedDomains?: string[];
}

interface SanitizationResult {
  success: boolean;
  sanitizedContent?: string;
  warnings: string[];
  blockedElements: string[];
  hash?: string;
}

export class SVGSanitizer {
  private logger: Logger;
  private purify: typeof DOMPurify;

  constructor(logger: Logger) {
    this.logger = logger;
    const window = new JSDOM('').window;
    this.purify = DOMPurify(window);
  }

  sanitize(svgContent: string, options: SanitizationOptions): SanitizationResult {
    const result: SanitizationResult = {
      success: false,
      warnings: [],
      blockedElements: []
    };

    // Size check
    if (Buffer.byteLength(svgContent, 'utf-8') > options.maxFileSize) {
      result.warnings.push('File exceeds maximum size limit');
      return result;
    }

    // Build forbidden tags based on options
    const forbiddenTags = ['script', 'foreignObject', 'iframe', 'embed', 'object'];
    if (!options.allowAnimations) {
      forbiddenTags.push('animate', 'animateMotion', 'animateTransform', 'set');
    }
    if (!options.allowExternalRefs) {
      forbiddenTags.push('use', 'image');
    }

    // Track blocked elements for logging
    this.purify.addHook('uponSanitizeElement', (node, data) => {
      if (forbiddenTags.includes(data.tagName)) {
        result.blockedElements.push(data.tagName);
      }
    });

    // Build forbidden attributes
    const forbiddenAttrs = [
      'onload', 'onclick', 'onerror', 'onmouseover', 'onmouseout',
      'onfocus', 'onblur', 'onanimationend', 'onanimationstart',
      'ontransitionend', 'formaction', 'data', 'srcdoc'
    ];

    // Handle href attributes specially
    this.purify.addHook('uponSanitizeAttribute', (node, data) => {
      if (data.attrName === 'href' || data.attrName === 'xlink:href') {
        const value = data.attrValue.toLowerCase().trim();

        // Block javascript: URLs
        if (value.startsWith('javascript:') || value.startsWith('data:')) {
          data.attrValue = '';
          result.blockedElements.push(`${data.attrName}="${value}"`);
          return;
        }

        // Validate external URLs if allowed
        if (options.allowExternalRefs && options.allowedDomains) {
          try {
            const url = new URL(value);
            if (!options.allowedDomains.includes(url.hostname)) {
              data.attrValue = '';
              result.warnings.push(`Blocked external reference to ${url.hostname}`);
            }
          } catch {
            // Relative URLs are allowed
          }
        } else if (!options.allowExternalRefs && value.startsWith('http')) {
          data.attrValue = '';
          result.blockedElements.push(`external href: ${value}`);
        }
      }
    });

    try {
      const sanitized = this.purify.sanitize(svgContent, {
        USE_PROFILES: { svg: true, svgFilters: true },
        FORBID_TAGS: forbiddenTags,
        FORBID_ATTR: forbiddenAttrs,
        ALLOW_DATA_ATTR: false,
        ADD_TAGS: options.allowAnimations ? 
          ['animate', 'animateMotion', 'animateTransform'] : [],
      });

      // Remove hooks to prevent memory leaks
      this.purify.removeAllHooks();

      // Final validation pass
      if (!this.validateSanitizedSVG(sanitized)) {
        result.warnings.push('Post-sanitization validation failed');
        return result;
      }

      result.success = true;
      result.sanitizedContent = sanitized;
      result.hash = createHash('sha256').update(sanitized).digest('hex');

      // Log if elements were blocked
      if (result.blockedElements.length > 0) {
        this.logger.warn('Blocked elements during SVG sanitization', {
          blocked: result.blockedElements,
          hash: result.hash
        });
      }

      return result;
    } catch (error) {
      this.logger.error('SVG sanitization error', { error });
      result.warnings.push('Sanitization processing error');
      return result;
    }
  }

  private validateSanitizedSVG(content: string): boolean {
    // Additional validation after sanitization
    const dangerousPatterns = [
      /javascript:/gi,
      /data:text\/html/gi,
      /on\w+\s*=/gi,
      /<script/gi,
      /expression\s*\(/gi,
      /url\s*\(\s*["']?javascript:/gi,
    ];

    return !dangerousPatterns.some(pattern => pattern.test(content));
  }
}

