const SANITIZE_CONFIG = {
  ALLOWED_TAGS: ['b', 'i', 'em', 'strong', 'a', 'p', 'br'],
  ALLOWED_ATTR: ['href', 'title'],
  ALLOW_DATA_ATTR: false,
  FORBID_TAGS: ['style', 'script', 'iframe', 'form', 'input'],
  FORBID_ATTR: ['onerror', 'onload', 'onclick', 'onmouseover', 'style']
};

// CSS property whitelist
const ALLOWED_CSS_PROPERTIES = ['color', 'background-color', 'font-size'];
const ALLOWED_CSS_VALUES = /^[a-zA-Z0-9#\s,()%]+$/;

function sanitizeCSS(cssString) {
  if (!cssString) return '';

  const sanitized = cssString
    .split(';')
    .filter(rule => {
      const [property, value] = rule.split(':').map(s => s.trim().toLowerCase());
      return ALLOWED_CSS_PROPERTIES.includes(property) && 
             ALLOWED_CSS_VALUES.test(value || '');
    })
    .join(';');

  return sanitized;
}

function UserProfile({ userId }) {
