  ],

  // DOMPurify configuration for rich content
  PURIFY_CONFIG: {
    ALLOWED_TAGS: ['b', 'i', 'em', 'strong', 'a', 'p', 'br', 'ul', 'ol', 'li', 
                   'h1', 'h2', 'h3', 'code', 'pre', 'blockquote', 'span'],
    ALLOWED_ATTR: ['href', 'title', 'class', 'data-language'],
    ALLOW_DATA_ATTR: false,
    FORBID_TAGS: ['script', 'style', 'iframe', 'object', 'embed', 'form', 
                  'input', 'textarea', 'button', 'select', 'svg', 'math'],
    FORBID_ATTR: ['onerror', 'onload', 'onclick', 'onmouseover', 'onfocus',
                  'onblur', 'onsubmit', 'onkeydown', 'onkeyup', 'style', 
                  'srcdoc', 'data'],
    ADD_ATTR: ['target'],
    FORCE_BODY: true,
    SANITIZE_DOM: true
  },

  // CSP nonce for inline scripts (generated per request)
  CSP_NONCE: null
};

// Custom DOMPurify hooks to catch bypass attempts
DOMPurify.addHook('uponSanitizeElement', (node, data) => {
  // Log potential XSS attempts for security monitoring
  if (data.tagName === 'script' || data.tagName === 'iframe') {
    console.warn('[Security] Blocked dangerous element:', data.tagName);
    logSecurityEvent('xss_attempt', { element: data.tagName });
  }
});

DOMPurify.addHook('uponSanitizeAttribute', (node, data) => {
  // Block javascript: URLs in all attributes
  if (data.attrValue && /^\s*javascript:/i.test(data.attrValue)) {
    data.attrValue = '';
    logSecurityEvent('xss_attempt', { attribute: data.attrName, value: 'javascript:' });
  }

  // Block data: URLs except for images with safe MIME types
  if (data.attrValue && /^\s*data:/i.test(data.attrValue)) {
    if (!/^data:image\/(png|jpeg|gif|webp);base64,/i.test(data.attrValue)) {
      data.attrValue = '';
      logSecurityEvent('xss_attempt', { attribute: data.attrName, type: 'data_url' });
    }
  }
});

// Security event logging
function logSecurityEvent(eventType, details) {
  fetch('/api/security/log', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      event: eventType,
      details,
      timestamp: new Date().toISOString(),
      url: window.location.href,
      userAgent: navigator.userAgent
    }),
    credentials: 'include'
  }).catch(() => {}); // Fire and forget
}

// Safe embed URL validator
function validateEmbedUrl(url) {
  try {
    const parsed = new URL(url);

    // Must be HTTPS
    if (parsed.protocol !== 'https:') {
      return { valid: false, reason: 'Must use HTTPS' };
    }

    // Must be from trusted domain
    const isTrusted = SECURITY_CONFIG.TRUSTED_EMBED_DOMAINS.some(
      domain => parsed.hostname === domain || parsed.hostname.endsWith('.' + domain)
    );

    if (!isTrusted) {
      return { valid: false, reason: 'Domain not in allowlist' };
    }

    // No credentials in URL
    if (parsed.username || parsed.password) {
      return { valid: false, reason: 'Credentials not allowed in URL' };
    }

    return { valid: true, sanitizedUrl: parsed.href };
  } catch (e) {
    return { valid: false, reason: 'Invalid URL format' };
  }
}

// Sandboxed iframe component for embeds
function SecureEmbed({ embedUrl, title }) {
  const [isValid, setIsValid] = useState(false);
  const [sanitizedUrl, setSanitizedUrl] = useState('');
  const [error, setError] = useState(null);
  const iframeId = useMemo(() => `embed-${uuidv4()}`, []);

  useEffect(() => {
    const validation = validateEmbedUrl(embedUrl);
    if (validation.valid) {
      setIsValid(true);
      setSanitizedUrl(validation.sanitizedUrl);
    } else {
      setIsValid(false);
      setError(validation.reason);
      logSecurityEvent('embed_blocked', { url: embedUrl, reason: validation.reason });
    }
  }, [embedUrl]);

  if (!isValid) {
    return (
      <div className="embed-error" role="alert">
        <span>Unable to load embed: {error || 'Invalid source'}</span>
      </div>
    );
  }

  return (
    <div className="secure-embed-container">
      <iframe
        id={iframeId}
        src={sanitizedUrl}
        title={DOMPurify.sanitize(title || 'Embedded content', { ALLOWED_TAGS: [] })}
        // CRITICAL: Restrictive sandbox prevents script execution and form submission
        sandbox="allow-scripts allow-same-origin"
        // Block all permissions
        allow=""
        // Referrer policy
        referrerPolicy="no-referrer"
        // Prevent embedding of sensitive content
        loading="lazy"
        // Explicit dimensions prevent clickjacking via resize
        width="560"
        height="315"
        style={{ border: 'none', maxWidth: '100%' }}
      />
    </div>
  );
}

// Code block component with syntax highlighting (no execution)
function SecureCodeBlock({ code, language }) {
  // Strip any potential script injections from code content
  const sanitizedCode = useMemo(() => {
    // Remove any HTML tags from code
    return (code || '')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;');
  }, [code]);

  const sanitizedLanguage = useMemo(() => {
    // Whitelist of allowed language identifiers
    const ALLOWED_LANGUAGES = ['javascript', 'python', 'java', 'go', 'rust', 
                               'html', 'css', 'sql', 'bash', 'json', 'text'];
    const lang = (language || 'text').toLowerCase().replace(/[^a-z]/g, '');
    return ALLOWED_LANGUAGES.includes(lang) ? lang : 'text';
  }, [language]);

  return (
    <pre className={`code-block language-${sanitizedLanguage}`}>
      <code dangerouslySetInnerHTML={{ __html: sanitizedCode }} />
    </pre>
  );
}

// Main rich content renderer
function RichContentProfile({ userId }) {
  const [profile, setProfile] = useState(null);
  const [error, setError] = useState(null);
  const [contentBlocks, setContentBlocks] = useState([]);

  useEffect(() => {
    const controller = new AbortController();

    fetch(`/api/users/${encodeURIComponent(userId)}/profile`, {
      credentials: 'include',
      signal: controller.signal,
      headers: {
        'Accept': 'application/json'
      }
    })
      .then(res => {
        if (!res.ok) throw new Error('Profile not found');
        return res.json();
      })
      .then(data => {
        setProfile(data);
        // Server should return structured content blocks, not raw HTML
        setContentBlocks(data.contentBlocks || []);
      })
      .catch(err => {
        if (err.name !== 'AbortError') {
          setError('Unable to load profile');
        }
      });

    return () => controller.abort();
  }, [userId]);

  // Render content block based on type
  const renderBlock = useCallback((block, index) => {
    const key = `block-${index}-${block.type}`;

    switch (block.type) {
      case 'text':
        // Sanitized rich text
        return (
          <div 
            key={key}
            className="content-block text-block"
            dangerouslySetInnerHTML={{ 
              __html: DOMPurify.sanitize(block.content, SECURITY_CONFIG.PURIFY_CONFIG)
            }}
          />
        );

      case 'code':
        // Code block with NO HTML rendering
        return (
          <SecureCodeBlock 
            key={key}
            code={block.content}
            language={block.language}
          />
        );

      case 'embed':
        // Sandboxed iframe for trusted sources only
        return (
          <SecureEmbed 
            key={key}
            embedUrl={block.url}
            title={block.title}
          />
        );

      case 'image':
        // Images with validated src
        const imgSrc = validateImageUrl(block.url);
        if (!imgSrc) return null;
        return (
          <img 
            key={key}
            src={imgSrc}
            alt={DOMPurify.sanitize(block.alt || '', { ALLOWED_TAGS: [] })}
            loading="lazy"
            className="content-image"
          />
        );

      default:
        logSecurityEvent('unknown_block_type', { type: block.type });
        return null;
    }
  }, []);

  if (error) return <div className="error-state">{error}</div>;
  if (!profile) return <div className="loading-state">Loading profile...</div>;

  return (
    <article className="rich-profile">
      {/* Plain text only for display name */}
      <h1>{DOMPurify.sanitize(profile.displayName || 'Anonymous', { ALLOWED_TAGS: [] })}</h1>

      {/* Structured content blocks */}
      <div className="profile-content">
        {contentBlocks.map(renderBlock)}
      </div>
    </article>
  );
}

// Image URL validator
function validateImageUrl(url) {
  try {
    const parsed = new URL(url);

    // Allow HTTPS and data URLs for images
    if (parsed.protocol === 'https:') {
      return parsed.href;
    }

    if (parsed.protocol === 'data:') {
      // Only allow safe image MIME types
      if (/^data:image\/(png|jpeg|gif|webp);base64,/.test(url)) {
        return url;
      }
    }

    return null;
  } catch {
    return null;
  }
}

export { RichContentProfile, SecureEmbed, SecureCodeBlock };
```

**Server-Side Validation (Node.js/Express):**

```javascript
const express = require('express');
const createDOMPurify = require('dompurify');
const { JSDOM } = require('jsdom');
const helmet = require('helmet');
const crypto = require('crypto');

const app = express();
const window = new JSDOM('').window;
const DOMPurify = createDOMPurify(window);

// Generate CSP nonce per request
app.use((req, res, next) => {
  res.locals.cspNonce = crypto.randomBytes(16).toString('base64');
  next();
});

// Strict Content Security Policy
app.use(helmet.contentSecurityPolicy({
  directives: {
    defaultSrc: ["'self'"],
    scriptSrc: [(req, res) => `'nonce-${res.locals.cspNonce}'`, "'strict-dynamic'"],
    styleSrc: ["'self'", "'unsafe-inline'"],
    imgSrc: ["'self'", 'data:', 'https:'],
    frameSrc: ['https://www.youtube.com', 'https://player.vimeo.com', 
               'https://codepen.io', 'https://codesandbox.io'],
    frameAncestors: ["'none'"],
    baseUri: ["'self'"],
    formAction: ["'self'"]
  }
}));

// Profile update endpoint with server-side sanitization
app.post('/api/profile/update', express.json({ limit: '100kb' }), async (req, res) => {
  try {
    const { contentBlocks } = req.body;

    if (!Array.isArray(contentBlocks) || contentBlocks.length > 50) {
      return res.status(400).json({ error: 'Invalid content format' });
    }

    const sanitizedBlocks = contentBlocks.map((block, index) => {
      // Validate block structure
      if (!block || typeof block.type !== 'string') {
        throw new Error(`Invalid block at index ${index}`);
      }

      switch (block.type) {
        case 'text':
          return {
            type: 'text',
            content: DOMPurify.sanitize(block.content || '', {
              ALLOWED_TAGS: ['b', 'i', 'em', 'strong', 'a', 'p', 'br'],
              ALLOWED_ATTR: ['href']
            })
          };

        case 'code':
          return {
            type: 'code',
            content: String(block.content || '').substring(0, 10000),
            language: /^[a-z]{1,20}$/.test(block.language) ? block.language : 'text'
          };

        case 'embed':
          // Server-side URL validation
          const embedValidation = validateServerSideEmbed(block.url);
          if (!embedValidation.valid) {
            throw new Error(`Invalid embed URL: ${embedValidation.reason}`);
          }
          return {
            type: 'embed',
            url: embedValidation.sanitizedUrl,
            title: DOMPurify.sanitize(block.title || '', { ALLOWED_TAGS: [] })
          };

        default:
          throw new Error(`Unknown block type: ${block.type}`);
      }
    });

    // Log the update for audit trail
    await logAuditEvent(req.user.id, 'profile_update', {
      blockCount: sanitizedBlocks.length,
      ip: req.ip
    });

    // Save sanitized content
    await saveUserProfile(req.user.id, { contentBlocks: sanitizedBlocks });

    res.json({ success: true });
  } catch (error) {
    console.error('Profile update error:', error);
    res.status(400).json({ error: 'Invalid content' });
  }
});

function validateServerSideEmbed(url) {
  const TRUSTED_DOMAINS = ['youtube.com', 'www.youtube.com', 'player.vimeo.com'];

  try {
    const parsed = new URL(url);
    if (parsed.protocol !== 'https:') {
      return { valid: false, reason: 'HTTPS required' };
    }
    if (!TRUSTED_DOMAINS.some(d => parsed.hostname === d)) {
      return { valid: false, reason: 'Untrusted domain' };
    }
    return { valid: true, sanitizedUrl: parsed.href };
  } catch {
    return { valid: false, reason: 'Invalid URL' };
  }
}
