  detectAngularGadgets(input: string): boolean {
    return this.ANGULAR_GADGET_PATTERNS.some(pattern => pattern.test(input));
  }

  // Safe text sanitization (no HTML allowed)
  sanitizeText(input: string, maxLength: number = 1000): string {
    if (!input || typeof input !== 'string') {
      return '';
    }

    // Check for Angular gadgets
    if (this.detectAngularGadgets(input)) {
      console.warn('Angular gadget attack detected and blocked');
      this.reportSecurityViolation('angular_gadget', input);
      return '';
