      "'self'",
      (req, res) => `'nonce-${res.locals.nonce}'`
    ],
    imgSrc: ["'self'", "data:", "https:"],
    fontSrc: ["'self'", "https://fonts.gstatic.com"],
    connectSrc: ["'self'", "https://api.example.com"],
    frameSrc: ["'none'"],
    frameAncestors: ["'none'"],
    objectSrc: ["'none'"],
    baseUri: ["'self'"],
    formAction: ["'self'"],
    upgradeInsecureRequests: [],
    blockAllMixedContent: [],
    // Trusted Types enforcement
    requireTrustedTypesFor: ["'script'"],
    trustedTypes: ["angular", "dompurify", "default"]
  },
  reportOnly: false
}));

// CSP violation reporting endpoint
app.post('/api/csp-report', express.json({ type: 'application/csp-report' }), (req, res) => {
  const violation = req.body['csp-report'];

  // Log and alert on violations
  console.error('CSP Violation:', JSON.stringify(violation, null, 2));

  // Send to SIEM/monitoring
  securityMonitor.reportViolation({
    type: 'csp_violation',
    directive: violation['violated-directive'],
    blockedUri: violation['blocked-uri'],
    documentUri: violation['document-uri'],
    sourceFile: violation['source-file'],
    lineNumber: violation['line-number'],
    timestamp: new Date().toISOString()
  });

  res.status(204).end();
});
```

**Defense in Depth Layers**:

1. **Trusted Types Policy**: Browser-enforced type safety for DOM sinks prevents all DOM-based XSS
```typescript
window.trustedTypes.createPolicy('angular', {
  createHTML: (input) => sanitize(input),
  createScript: () => { throw new Error('Blocked'); },
  createScriptURL: (url) => validateAllowlist(url)
});
```

2. **Multi-layer Sanitization**: DOMPurify + Angular sanitizer + custom filters
```typescript
const purified = DOMPurify.sanitize(html, strictConfig);
const angularSanitized = sanitizer.sanitize(SecurityContext.HTML, purified);
return sanitizer.bypassSecurityTrustHtml(angularSanitized);
```

3. **Angular Gadget Detection**: Pattern matching for known attack vectors
```typescript
const gadgetPatterns = [/constructor/, /__proto__/, /ng-app/];
if (gadgetPatterns.some(p => p.test(input))) {
  blockAndReport(input);
}
```

**Additional Protections**:
- **strict-dynamic CSP**: Only scripts loaded by trusted scripts can execute, blocking JSONP bypasses
- **Per-request nonces**: Cryptographically random, cannot be predicted by attackers
- **CSP violation reporting**: Real-time monitoring of bypass attempts
- **No unsafe-eval**: Blocks Angular JIT compiler exploits in production
- **Trusted Types enforcement**: Browser-level protection against DOM XSS sinks
- **DOMPurify hooks**: Additional sanitization for data: URIs and event handlers
- **Allowlist-based URL validation**: Only pre-approved origins for external resources
